 35	  int decoded_result = 0;
 36	
 37	  // Check if we got a NULL pointer and if buffer length is >= minimum length expected for the message.
 38	  CHECK_PDU_POINTER_AND_LENGTH_DECODER(buffer, PDN_CONNECTIVITY_REQUEST_MINIMUM_LENGTH, len);
 39	
 40	  /* Decoding mandatory fields */
 41	  if ((decoded_result = decode_u8_request_type(&pdn_connectivity_request->pdntype, 0, *(buffer + decoded) >> 4, len - decoded)) < 0)
 42	    return decoded_result;
 43	
 44	  if ((decoded_result = decode_u8_pdn_type(&pdn_connectivity_request->requesttype, 0, *(buffer + decoded) & 0x0f, len - decoded)) < 0)
 45	    return decoded_result;
 46	
 47	  decoded++;
 48	
 49	  /* Decoding optional fields */
 50	  while(len - decoded > 0) {
 51	    uint8_t ieiDecoded = *(buffer + decoded);
 52	
 53	    /* Type | value iei are below 0x80 so just return the first 4 bits */
 54	    if (ieiDecoded >= 0x80)
 55	      ieiDecoded = ieiDecoded & 0xf0;
 56	
 57	    switch(ieiDecoded) {
 58	    case PDN_CONNECTIVITY_REQUEST_ESM_INFORMATION_TRANSFER_FLAG_IEI:
 59	      if ((decoded_result =
 60	             decode_esm_information_transfer_flag(&pdn_connectivity_request->esminformationtransferflag,
 61	                 PDN_CONNECTIVITY_REQUEST_ESM_INFORMATION_TRANSFER_FLAG_IEI,
 62	                 buffer + decoded, len - decoded)) <= 0)
 63	        return decoded_result;
 64	
 65	      decoded += decoded_result;
 66	      /* Set corresponding mask to 1 in presencemask */
 67	      pdn_connectivity_request->presencemask |= PDN_CONNECTIVITY_REQUEST_ESM_INFORMATION_TRANSFER_FLAG_PRESENT;
 68	      break;
 69	
 70	    case PDN_CONNECTIVITY_REQUEST_ACCESS_POINT_NAME_IEI:
 71	      if ((decoded_result =
 72	             decode_access_point_name(&pdn_connectivity_request->accesspointname,
 73	                                      PDN_CONNECTIVITY_REQUEST_ACCESS_POINT_NAME_IEI, buffer +
 74	                                      decoded, len - decoded)) <= 0)
 75	        return decoded_result;
 76	
 77	      decoded += decoded_result;
 78	      /* Set corresponding mask to 1 in presencemask */
 79	      pdn_connectivity_request->presencemask |= PDN_CONNECTIVITY_REQUEST_ACCESS_POINT_NAME_PRESENT;
 80	      break;
 81	
 82	    case PDN_CONNECTIVITY_REQUEST_PROTOCOL_CONFIGURATION_OPTIONS_IEI:
 83	      if ((decoded_result =
 84	             decode_protocol_configuration_options(&pdn_connectivity_request->protocolconfigurationoptions,
 85	                 PDN_CONNECTIVITY_REQUEST_PROTOCOL_CONFIGURATION_OPTIONS_IEI,
 86	                 buffer + decoded, len - decoded)) <= 0)
 87	        return decoded_result;
 88	
 89	      decoded += decoded_result;
 90	      /* Set corresponding mask to 1 in presencemask */
 91	      pdn_connectivity_request->presencemask |= PDN_CONNECTIVITY_REQUEST_PROTOCOL_CONFIGURATION_OPTIONS_PRESENT;
 92	      break;
 93	
 94	    default:
 95	      errorCodeDecoder = TLV_DECODE_UNEXPECTED_IEI;
 96	      return TLV_DECODE_UNEXPECTED_IEI;
 97	    }
 98	  }
 99	
100	  return decoded;
101	}
